// Reads an entire text file and returns its contents as a single string.
// Used to load GLSL shader source files from disk at runtime.
std::string slurp(std::string fileName) {
  std::fstream file(fileName);
  std::string returnValue = "";
  while (file.good()) {
    std::string line;
    getline(file, line);
    returnValue += line + "\n";
  }
  return returnValue;
}

