// ─────────────────────────────────────────────────────────────────────────────
// Mat5d
// ─────────────────────────────────────────────────────────────────────────────
// A 5×5 double-precision matrix. The 5th row/column is the homogeneous
// coordinate — always [0,0,0,0,1] — so the top-left 4×4 block is the
// actual linear transform applied to the attractor points.
class Mat5d : public Mat<5, double> {
 public:
  // Fill the matrix with seeded random values in [-1,1], then enforce the
  // homogeneous row constraint (row 4 = [0,0,0,0,1]).
  void coefficients(int seed) {
    rnd::Random<> rng;
    rng.seed(seed);
    for (int k = 0; k < size(); k++) mElems[k] = rng.uniformS();
    mElems[4] = mElems[9] = mElems[14] = mElems[19] = 0;
    mElems[24] = 1;
  }
  // Flatten the matrix into a 25-element array for serialization and blending.
  std::array<double, 25> toArray() {
    std::array<double, 25> a;
    for (int k = 0; k < 25; k++) a[k] = mElems[k];
    return a;
  }
};

// ─────────────────────────────────────────────────────────────────────────────
// wrapture helpers
// ─────────────────────────────────────────────────────────────────────────────

// Core iteration kernel: seeds a random starting point, iterates it through
// matrix m 'count' times, and wraps each coordinate into [-b, b] after every
// step. Appends all points to v. Returns the determinant of m so callers can
// filter out degenerate attractors.
static double wraptureRun(std::vector<Vec4d> &v, double b, Mat5d &m, int seed,
                          int count) {
  rnd::Random<> rng;
  rng.seed(seed);
  Vec5d x(rng.ball<Vec4d>(), 1);
  v.push_back(x.elems());
  for (int i = 0; i < count; i++) {
    x = m * x;
    for (int k = 0; k < x.size() - 1; k++)
      x.elems()[k] = gam::scl::wrap(x.elems()[k], b, -b);
    v.push_back(x.elems());
  }
  return determinant(m);
}

// Build matrix from seed, then run the iteration kernel.
double wrapture(std::vector<Vec4d> &v, double b, int seed, int count) {
  Mat5d m;
  m.coefficients(seed);
  return wraptureRun(v, b, m, seed, count);
}

// Build matrix from a flat 25-element array, then run the iteration kernel.
// Used during blend transitions where the matrix is a lerp of two seeded matrices.
double wraptureFromArray(std::vector<Vec4d> &v, double b,
                         std::array<double, 25> &mat, int seed, int count) {
  Mat5d m;
  for (int k = 0; k < 25; k++) m.elems()[k] = mat[k];
  m.elems()[4] = m.elems()[9] = m.elems()[14] = m.elems()[19] = 0;
  m.elems()[24] = 1;
  return wraptureRun(v, b, m, seed, count);
}

