// Matrix layout note
// AlloLib Mat<5,double> is column-major: index = col*5 + row.
// Row 4 (homogeneous) is always [0,0,0,0,1] — fixed, not exposed.
// matSliders[row][col] maps to mElems[col*5 + row].
// ─────────────────────────────────────────────────────────────────────────────

// ─────────────────────────────────────────────────────────────────────────────
// Granular synthesis helpers (no Gamma dependency beyond gam::Sine)
// ─────────────────────────────────────────────────────────────────────────────

// Linear attack/decay amplitude envelope for a single grain.
// Internally a three-state machine: IDLE → ATTACK → DECAY → IDLE.
struct GrainEnv {
  float val = 0, inc = 0;
  int atkSamp = 0, dcySamp = 0, remaining = 0;
  enum { IDLE, ATTACK, DECAY } phase = IDLE;

  // Set attack/decay durations and start the envelope from zero.
  void trigger(float atkSec, float dcySec, float sr = 44100.f) {
    atkSamp = std::max(1, (int)(atkSec * sr));
    dcySamp = std::max(1, (int)(dcySec * sr));
    val = 0.f;  inc = 1.f / atkSamp;
    phase = ATTACK;
  }
  // Advance one sample and return the current amplitude; auto-idles at end of decay.
  float operator()() {
    if (phase == IDLE) return 0.f;
    val += inc;
    if (phase == ATTACK && val >= 1.f) {
      val = 1.f;  inc = -1.f / dcySamp;  phase = DECAY;
    } else if (phase == DECAY && val <= 0.f) {
      val = 0.f;  phase = IDLE;
    }
    return val;
  }
  bool done() const { return phase == IDLE; }
};

// A single granular voice: one sine oscillator plus a GrainEnv.
// trigger() sets frequency and envelope shape; operator()() produces one sample
// and deactivates the grain when the envelope finishes.
struct Grain {
  gam::Sine<> osc;
  GrainEnv    env;
  bool active = false;
  void trigger(float hz, float atkSec, float dcySec) {
    osc.freq(hz);
    env.trigger(atkSec, dcySec);
    active = true;
  }
  float operator()() {
    if (!active) return 0.f;
    float s = osc() * env();
    if (env.done()) active = false;
    return s;
  }
};

// ─────────────────────────────────────────────────────────────────────────────
// Resonator — classic 2-pole resonant band-pass (no Gamma dependency)
//   freq : center frequency in Hz
//   res  : pole radius [0,1) — closer to 1 = narrower, longer ring
// ─────────────────────────────────────────────────────────────────────────────
// Classic 2-pole IIR resonant bandpass ("reson") filter.
// set() computes coefficients; operator()(x) filters one sample.
// gain is normalized so the peak response is approximately 1.
struct Resonator {
  float y1 = 0, y2 = 0, a1 = 0, a2 = 0, gain = 1;
  void set(float freq, float res, float sr = 44100.f) {
    float w = 2.f * float(M_PI) * freq / sr;
    a1   = 2.f * res * std::cos(w);
    a2   = -(res * res);
    gain = (1.f - res * res) * 0.5f;  // normalise peak to ~1
  }
  float operator()(float x) {
    float y = gain * x + a1 * y1 + a2 * y2;
    y2 = y1;  y1 = y;
    return y;
  }
};

// ─────────────────────────────────────────────────────────────────────────────
// SimpleReverb — Freeverb-style: 4 comb filters parallel + 2 allpass in series
// ─────────────────────────────────────────────────────────────────────────────
// Freeverb-inspired reverb network.
// 4 comb filters (with internal lowpass damping) run in parallel; their summed
// output passes through 2 allpass filters in series.
// Delay lengths are prime-ish integers tuned for 44100 Hz to avoid resonance overlap.
struct SimpleReverb {
  static constexpr int NC = 4, NA = 2;
  // Delay lengths tuned for 44100 Hz (prime-ish to avoid resonance overlap)
  static constexpr int CD[NC] = {1116, 1188, 1277, 1356};
  static constexpr int AD[NA] = {556, 441};

  std::vector<float> cbuf[NC], abuf[NA];
  int ci[NC]{}, ai[NA]{};
  float cfbk[NC]{}, cstate[NC]{};  // comb feedback + lowpass state
  float damp = 0.4f, afbk = 0.5f;

  // Allocate delay buffers and compute per-comb feedback coefficients from
  // the target decay time in seconds.
  void init(float sr = 44100.f, float decaySec = 4.f) {
    for (int i = 0; i < NC; i++) {
      cbuf[i].assign(CD[i], 0.f);
      cfbk[i] = std::pow(0.001f, CD[i] / (sr * decaySec));
    }
    for (int i = 0; i < NA; i++) abuf[i].assign(AD[i], 0.f);
  }

  // Process one sample through the full comb + allpass network.
  float operator()(float in) {
    float out = 0;
    for (int i = 0; i < NC; i++) {
      float d = cbuf[i][ci[i]];
      cstate[i] = d * (1.f - damp) + cstate[i] * damp;
      cbuf[i][ci[i]] = in + cstate[i] * cfbk[i];
      ci[i] = (ci[i] + 1) % CD[i];
      out += d;
    }
    out *= 0.25f;
    for (int i = 0; i < NA; i++) {
      float d = abuf[i][ai[i]];
      abuf[i][ai[i]] = out + d * afbk;
      ai[i] = (ai[i] + 1) % AD[i];
      out = d - afbk * out;
    }
    return out;
  }
};

